INSERT INTO public.traffic_signs (number, category, title, description, image_path, order_index) VALUES
('1.1', 'Ogohlantiruvchi belgilar', 'Shlagbaumli temir yo‘l kesishmasi', '', '1.1_resize-min.png.webp', 0),
('1.2', 'Ogohlantiruvchi belgilar', 'Shlagbaumsiz temir yo‘l kesishmasi', '', '1.2_resize-min.png.webp', 1),
('1.3.1', 'Ogohlantiruvchi belgilar', 'Bir izli temir yo‘l', 'Bir izli temir yo’l belgilari shlagbaum bilan jihozlanmagan temir yo’l kesishmasi oldida o’rnatiladi.', '1.3.1_resize-min.png', 2),
('1.3.2', 'Ogohlantiruvchi belgilar', 'Ko‘p izli temir yo‘l', 'Ikki va undan ortiq izli temir yo’l belgilari shlagbaum bilan jihozlanmagan temir yo’l kesishmasi oldida o’rnatiladi.', '1.3.2_resize-min.png.webp', 3),
('1.4.1 – 1.4.6', 'Ogohlantiruvchi belgilar', 'Temir yo‘l kesishmasiga yaqinlashuv', 'Aholi punktlaridan tashqarida temir yo‘l kesishmasiga yaqinlashayotganlik haqida qo‘shimcha ogohlantirish beradi.', '1.4_resize-230x300.png.webp', 4),
('1.5', 'Ogohlantiruvchi belgilar', 'Tramvay yo‘li bilan kesishuv', '', '1.5_resize-min.png.webp', 5),
('1.6', 'Ogohlantiruvchi belgilar', 'Teng ahamiyatli yo‘llar kesishuvi', '', '1.6_resize-min.png.webp', 6),
('1.7', 'Ogohlantiruvchi belgilar', 'Aylanma harakatlanish bilan kesishuv', '', '1.7_resize-min.png.webp', 7),
('1.8', 'Ogohlantiruvchi belgilar', 'Svetofor bilan tartibga solish', 'Harakatlanish svetofor bilan tartibga solinadigan chorraha, piyodalar o‘tish joyi yoki yo‘l qismini bildiradi.', '1.8_resize-min.png.webp', 8),
('1.9', 'Ogohlantiruvchi belgilar', 'Ko‘tarma ko‘prik', 'Ko‘tarma ko‘prik yoki solda kesib o‘tish.', '1.9_resize-min.png.webp', 9),
('1.10', 'Ogohlantiruvchi belgilar', 'Sohilga chiqish', 'Daryo yoki suv havzasi qirg‘og‘iga chiqishni bildiradi.', '1.10_resize-min.png.webp', 10),
('1.11.1', 'Ogohlantiruvchi belgilar', 'Xavfli burilish o‘ngga', 'O‘ngga yo‘l belgilari yo‘lning kichik radiusli yoki ko‘rinishi cheklangan burilish joyini bildiradi.', '1.11.1_resize-min.png.webp', 11),
('1.11.2', 'Ogohlantiruvchi belgilar', 'Xavfli burilish chapga', 'Chapga yo‘l belgilari yo‘lning kichik radiusli yoki ko‘rinishi cheklangan burilish joyini bildiradi.', '1.11.2_resize-min.png.webp', 12),
('1.12.1', 'Ogohlantiruvchi belgilar', 'Xavfli burilishlar', 'Birinchi burilish o‘ngga yo‘l belgilari yo‘lning xavfli burilishlari bo‘lgan qismini bildiradi.', '1.12.1_resize-min.png.webp', 13),
('1.12.2', 'Ogohlantiruvchi belgilar', 'Xavfli burilishlar', 'Birinchi burilish chapga yo‘l belgilari yo‘lning xavfli burilishlari bo‘lgan qismini bildiradi.', '1.12.2_resize-min.png.webp', 14),
('1.13', 'Ogohlantiruvchi belgilar', 'Tik nishablik', '', '1.13_resize-min.png.webp', 15),
('1.14', 'Ogohlantiruvchi belgilar', 'Tik balandlik', '', '1.14_resize-min.png.webp', 16),
('1.15', 'Ogohlantiruvchi belgilar', 'Sirpanchiq yo‘l', 'Qatnov qismi o‘ta sirpanchiq bo‘lgan yo‘l qismi.', '1.15_resize-min.png.webp', 17),
('1.16', 'Ogohlantiruvchi belgilar', 'Notekis yo‘l', 'Qatnov qismi notekis bo‘lgan yo‘l (o‘nqir-cho‘nqir, o‘ydim-chuqur joylar, ko‘prikning yo‘lga notekis tutashuvi va shu kabilar) qismini bildiradi.', '1.16_resize-min.png.webp', 18),
('1.17', 'Ogohlantiruvchi belgilar', 'Tosh otilishi xavfi', 'Transport vositasining g‘ildiragi ostidan shag‘al, tosh va shunga o‘xshashlarning otilib chiqish ehtimoli bo‘lgan yo‘l qismini bildiradi.', '1.17_resize-min.png.webp', 19),
('1.18.1', 'Ogohlantiruvchi belgilar', 'Yo‘lning torayishi', 'Ikki tomonlama torayish', '1.18.1_resize-min.png.webp', 20),
('1.18.2', 'Ogohlantiruvchi belgilar', 'Yo‘lning torayishi', 'O‘ngga torayish', '1.18.2_resize-min.png.webp', 21),
('1.18.3', 'Ogohlantiruvchi belgilar', 'Yo‘lning torayishi', 'Chapga torayish', '1.18.3_resize-min.png.webp', 22),
('1.19', 'Ogohlantiruvchi belgilar', 'Ikki tomonlama harakatlanish', 'Yo‘lning (qatnov qismining) qarama-qarshi harakatlanish qismi boshlanishini bildiradi.', '1.19_resize-min.png.webp', 23),
('1.20', 'Ogohlantiruvchi belgilar', 'Piyodalar o‘tish joyi', '5.16.1, 5.16.2, 5.48 belgilari va (yoki) 1.14.1 — 1.14.4, 1.29.1 — 1.29.3 yo‘l chiziqlari bilan belgilangan piyodalar o‘tish joyini bildiradi.', '1.20_resize-min.png.webp', 24),
('1.21', 'Ogohlantiruvchi belgilar', 'Bolalar', 'Bolalar muassasasi (maktablar, bolalarning dam olish maskanlari va shunga o‘xshashlar)ga yaqin yo‘lning qatnov qismidan bolalarning chiqib qolish ehtimolini bildiradi.', '1.21_resize-min.png.webp', 25),
('1.22', 'Ogohlantiruvchi belgilar', 'Velosiped yo‘lkasi bilan kesishuv', '', '1.22_resize-min.png.webp', 26),
('1.23', 'Ogohlantiruvchi belgilar', 'Ta’mirlash ishlari', '', '1.23_resize-min.png.webp', 27),
('1.24', 'Ogohlantiruvchi belgilar', 'Mol haydab o‘tish', '', '1.24_resize-min.png.webp', 28),
('1.25.1', 'Ogohlantiruvchi belgilar', 'Yovvoyi hayvonlar', '', '1.25.1_resize-min.png.webp', 29),
('1.25.2', 'Ogohlantiruvchi belgilar', 'Pastlab uchuvchi qushlar', '', '1.25.2_resize-min.png.webp', 30),
('1.25.3', 'Ogohlantiruvchi belgilar', 'Kemiruvchi va sudralib yuruvchi hayvonlar', '', '1.25.3_resize-min.png.webp', 31),
('1.26', 'Ogohlantiruvchi belgilar', 'Toshlar tushishi', 'Tosh ko‘chishi, surilishi va tushishi mumkin bo‘lgan yo‘l qismini bildiradi.', '1.26_resize-min.png.webp', 32),
('1.27', 'Ogohlantiruvchi belgilar', 'Yonlama shamol', '', '1.27_resize-min.png.webp', 33),
('1.28', 'Ogohlantiruvchi belgilar', 'Pastlab uchuvchi samolyotlar', '', '1.28_resize.png.webp', 34),
('1.29', 'Ogohlantiruvchi belgilar', 'Tunnel', 'Sun’iy ravishda yoritilmagan yoki kirish peshtog‘ining ko‘rinishi cheklangan tunnelni bildiradi.', '1.29_resize-min.png.webp', 35),
('1.30', 'Ogohlantiruvchi belgilar', 'Boshqa xavf-xatarlar', 'Ogohlantiruvchi belgilarda ko‘zda tutilmagan xavf-xatarlar bo‘lgan yo‘l qismini bildiradi.', '1.30_resize-min.png.webp', 36),
('1.31', 'Ogohlantiruvchi belgilar', 'Sun’iy yo‘l notekisligi', 'Yo‘lning sun’iy notekislik o‘rnatilgan qismiga yaqinlashayotganligi to‘g‘risida ogohlantiradi. Transport vositasining harakatlanish tezligini majburiy tarzda kamaytirish uchun qo‘llaniladi.', '1.31_resize-min.png.webp', 37),
('1.31.1 – 1.31.2', 'Ogohlantiruvchi belgilar', 'Burilishning yo‘nalishi', 'Kichik radiusli, ko‘rinishi cheklangan yo‘lda harakatlanish yo‘nalishini va yo‘lning ta’mirlanayotgan qismini aylanib o‘tish yo‘nalishini bildiradi.', '1.31.1_resize-min.png.webp', 38),
('1.31.3', 'Ogohlantiruvchi belgilar', 'Burilishning yo‘nalishi', 'T-simon chorrahada yoki yo‘l ayrilishlarida harakatlanish yo‘nalishini, ta’mirlanayotgan yo‘l qismini aylanib o‘tish yo‘nalishini bildiradi.', '1.31.3_resize-min.png', 39),
('1.32', 'Ogohlantiruvchi belgilar', 'Tirbandlik', 'Ushbu yo‘l belgisi vaqtinchalik yoki tasviri o‘zgaradigan holatda tirbandlik hosil bo‘lgan yo‘l yoki chorrahaga kirish oldidan yo‘lni yoki chorrahani aylanib o‘tish imkoniyati bo‘lgan joyga o‘rnatiladi.', '1.32_resize-min.png.webp', 40),
('1.33', 'Ogohlantiruvchi belgilar', 'Qatnov qismi kesishmasi hududi', '1. 30 yotiq chizig‘i bilan belgilangan chorrahaga yaqinlashayotganligini anglatib, oldinda tirbandlik yuzaga kelganligi tufayli majburiy to‘xtab, ko‘ndalang yo‘nalishdagi transport vositalarining harakatlanishiga to‘sqinlik tug‘diradigan bo‘lsa, chorrahaga kirish, agar to‘xtash chizig‘i yoki 5.33 yo‘l belgisidan o‘tib bo‘lgan haydovchiga esa qatnov qismlari kesishmasiga kirishni taqiqlanishini bildiradi.', '1.33_resize-min.png.webp', 41),
('1.34', 'Ogohlantiruvchi belgilar', 'Diqqat, boshqariladigan to‘siq', 'Ushbu yo‘l belgisi boshqariladigan to‘suvchi qurilmasiga yetmasdan o‘rnatiladi va transport vositalari haydovchilarini oldinda to‘suvchi qurilma borligi haqida ogohlantiradi.', '1.34_resize-min.png.webp', 42),
('1.35', 'Ogohlantiruvchi belgilar', 'Piyodalarning yo‘l yoqasidan yurishi mumkin bo‘lgan hudud', '', '1.35_resize-min.png.webp', 43),
('2.1', 'Imtiyoz belgilari', 'Asosiy yo‘l', 'Harakat tartibga solinmagan chorrahalarda oldin o‘tish huquqini beradi. Belgi asosiy yo‘l boshiga va chorrahalarning bevosita oldiga o‘rnatiladi.', '2.1_resize-min.png', 44),
('2.2', 'Imtiyoz belgilari', 'Asosiy yo‘lning oxiri', '', '2.2_resize-min.png', 45),
('2.3.1', 'Imtiyoz belgilari', 'Ikkinchi darajali yo‘l bilan kesishuv', 'Yo‘l belgilari aholi punktlarida kesishmagacha 50 — 100 metr masofada, aholi punktlaridan tashqarida esa 150 — 300 metr masofada o‘rnatiladi.', '2.3.1.1_resize-min.png.webp', 46),
('2.3.2', 'Imtiyoz belgilari', 'Ikkinchi darajali yo‘l bilan tutashuv o‘ngdan', 'Yo‘l belgilari aholi punktlarida kesishmagacha 50 — 100 metr masofada, aholi punktlaridan tashqarida esa 150 — 300 metr masofada o‘rnatiladi.', '2.3.2.1_resize-min.png.webp', 47),
('2.3.3', 'Imtiyoz belgilari', 'Ikkinchi darajali yo‘l bilan tutashuv chapdan', 'Yo‘l belgilari aholi punktlarida kesishmagacha 50 — 100 metr masofada, aholi punktlaridan tashqarida esa 150 — 300 metr masofada o‘rnatiladi.', '2.3.3.1_resize-min.png.webp', 48),
('2.4', 'Imtiyoz belgilari', 'Yo‘l bering', 'Haydovchi kesib o‘tilayotgan yo‘ldan, 7.13 qo‘shimcha-axborot belgisi bo‘lganda esa asosiy yo‘ldan harakatlanayotgan transport vositasiga yo‘l berishi kerak.', '2.4_resize-min.png.webp', 49),
('2.5', 'Imtiyoz belgilari', 'To‘xtamasdan harakatlanish taqiqlangan', 'To‘xtash chizig‘i oldida, agar u bo‘lmasa, kesib o‘tiladigan qatnov qismining chetida to‘xtamasdan harakatlanish taqiqlanadi. Haydovchi kesib o‘tilayotgan yo‘ldan, 7.13 qo‘shimcha-axborot belgisi bo‘lganda esa asosiy yo‘ldan harakatlanayotgan transport vositalariga yo‘l berishi kerak. Bu belgi temir yo‘l kesishmasi yoki karantin maskanidan oldin o‘rnatilishi mumkin. Bunday hollarda haydovchi to‘xtash chizig‘i oldida, u bo‘lmasa, belgi oldida to‘xtashi kerak.', '2.5_resize-min.png.webp', 50),
('2.6', 'Imtiyoz belgilari', 'Ro‘para harakatlanishning ustunligi', 'Qarama-qarshi harakatlanishni qiyinlashtiradigan hollarda yo‘lning tor qismiga kirish taqiqlanadi. Haydovchi yo‘lning tor qismida bo‘lgan yoki ro‘paradan unga yaqin bo‘lgan transport vositasiga yo‘l berishi kerak.', '2.6_resize-min.png.webp', 51),
('2.7', 'Imtiyoz belgilari', 'Ro‘paradagi harakatlanishga nisbatan imtiyoz', 'Yo‘lning tor qismida harakatlanishda haydovchi ro‘paradan kelayotgan transport vositasiga nisbatan imtiyozga egaligini bildiradi.', '2.7_resize-min.png.webp', 52),
('3.1', 'Taqiqlovchi belgilar', 'Kirish taqiqlangan', 'Barcha transport vositalarining kirishi taqiqlanishini bildiradi.', '3.1_resize-min.png.webp', 53),
('3.2', 'Taqiqlovchi belgilar', 'Harakatlanish taqiqlangan', 'Barcha transport vositalarining harakatlanishi taqiqlanishini bildiradi.', '3.2_resize-min.png.webp', 54),
('3.3', 'Taqiqlovchi belgilar', 'Mexanik transport vositalarining harakatlanishi taqiqlangan', '', '3.3_resize-min.png.webp', 55),
('3.4', 'Taqiqlovchi belgilar', 'Yuk avtomobillarining harakatlanishi taqiqlangan', 'Ruxsat etilgan to‘liq vazni 3,5 tonnadan (agar vazni belgida ko‘rsatilmagan bo‘lsa) yoki ruxsat etilgan to‘liq vazni belgida ko‘rsatilgandan ortiq bo‘lgan yuk avtomobillari va transport vositalari tarkiblarining, shuningdek traktorlar, o‘ziyurar uskunalarning harakatlanishi taqiqlanadi. 3.4. yo‘l belgisi bortlariga qiya oq chiziq tortilgan yoki odamlarni tashish uchun mo‘ljallangan yuk avtomobillarining harakatlanishini taqiqlamaydi.', '3.4_resize-min.png.webp', 56),
('3.5', 'Taqiqlovchi belgilar', 'Mototsikllar harakatlanishi taqiqlangan', '', '3.5_resize-min.png.webp', 57),
('3.6', 'Taqiqlovchi belgilar', 'Traktorlar harakatlanishi taqiqlangan', 'Traktorlar va o‘ziyurar uskunalarning harakatlanishi taqiqlanadi.', '3.6_resize-min.png.webp', 58),
('3.7', 'Taqiqlovchi belgilar', 'Tirkama bilan harakatlanish taqiqlangan', 'Yuk avtomobillari va traktorlarning barcha turdagi tirkamalar bilan harakatlanishi, shuningdek, mexanik transport vositalarini shatakka olish taqiqlanadi.', '3.7_resize-min.png.webp', 59),
('3.8', 'Taqiqlovchi belgilar', 'Ot-arava harakatlanishi taqiqlangan', 'Ot-arava (chana), otliqlar, yuk ortilgan hayvonlarning harakatlanishi, shuningdek, chorva (poda) haydab o‘tish taqiqlanadi.', '3.8_resize-min.png.webp', 60),
('3.9', 'Taqiqlovchi belgilar', 'Velosipedda harakatlanish taqiqlangan', 'Velosipedda va mopedda harakatlanish taqiqlanadi.', '3.9_resize-min.png.webp', 61),
('3.10', 'Taqiqlovchi belgilar', 'Piyodaning harakatlanishi taqiqlangan', '', '3.10_resize-min.png.webp', 62),
('3.11', 'Taqiqlovchi belgilar', 'Vazn cheklangan', 'Haqiqiy umumiy vazni belgida ko‘rsatilganidan ortiq bo‘lgan transport vositalarining, shuningdek, transport vositalari tarkiblarining harakatlanishi taqiqlanadi.', '3.11_resize.png.webp', 63),
('3.12', 'Taqiqlovchi belgilar', 'O‘qqa tushadigan og‘irlik cheklangan', 'Har qanday o‘qiga tushadigan haqiqiy og‘irlik belgida ko‘rsatilganidan ortiq bo‘lgan transport vositalarining harakatlanishi taqiqlanadi.', '3.12_resize-min.png.webp', 64),
('3.13', 'Taqiqlovchi belgilar', 'Cheklangan balandlik', 'Gabarit balandligi (yuk bilan yoki yuksiz) belgida ko‘rsatilgandan ortiq bo‘lgan transport vositalarining harakatlanishi taqiqlanadi.', '3.13_resize.png.webp', 65),
('3.14', 'Taqiqlovchi belgilar', 'Cheklangan kenglik', 'Gabarit kengligi (yuk bilan yoki yuksiz) belgida ko‘rsatilganidan ortiq bo‘lgan transport vositalarining harakatlanishi taqiqlanadi.', '3.14_resize.png.webp', 66),
('3.15', 'Taqiqlovchi belgilar', 'Cheklangan uzunlik', 'Gabarit uzunligi (yuk bilan yoki yuksiz) belgida ko‘rsatilganidan ortiq bo‘lgan transport vositalari (transport vositalari tarkiblari)ning harakatlanishi taqiqlanadi.', '3.15_resize-min.png.webp', 67),
('3.16', 'Taqiqlovchi belgilar', 'Eng kam oraliq', 'Belgida ko‘rsatilganidan kam bo‘ylama oraliq masofada harakatlanish taqiqlanadi.', '3.16_resize-min.png.webp', 68),
('3.17.1', 'Taqiqlovchi belgilar', 'Bojxona', 'Bojxona (nazorat punkti) oldida to‘xtamasdan o‘tib ketish taqiqlanadi.', '3.17.1_resize-min.png.webp', 69),
('3.17.2', 'Taqiqlovchi belgilar', 'Xavf-xatar', 'Yo‘l-transport hodisasi, avariya, yong‘in yoki boshqa xavf-xatar vaziyatlar tufayli, istisnosiz, barcha transport vositalarining bundan keyin harakatlanishi taqiqlanadi.', '3.17.2_resize-min.png.webp', 70),
('3.17.3', 'Taqiqlovchi belgilar', 'Nazorat joyi', 'Transport vositalarining tekshirib o‘tkazilishi majburiy bo‘lgan vaqtincha yoki doimiy nazorat punktlarida o‘rnatiladi. Ushbu yo‘l belgisi 2.5 yo‘l belgisi bilan birga o‘rnatilishi mumkin.', '3.17.3_resize-min.png.webp', 71),
('3.18.1', 'Taqiqlovchi belgilar', 'O‘ngga burilish taqiqlangan', '', '3.18.1_resize-min.png.webp', 72),
('3.18.2', 'Taqiqlovchi belgilar', 'Chapga burilish taqiqlanadi', '', '3.18.2_resize-min.png.webp', 73),
('3.19', 'Taqiqlovchi belgilar', 'Qayrilish taqiqlangan', '', '3.19_resize-min.png.webp', 74),
('3.20', 'Taqiqlovchi belgilar', 'Quvib o‘tish taqiqlangan', 'Soatiga 40 km dan kam tezlikda harakatlanayotgan yakka transport vositasidan boshqa transport vositalarini quvib o‘tish taqiqlanishini bildiradi.', '3.20_resize-min.png.webp', 75),
('3.21', 'Taqiqlovchi belgilar', 'Quvib o‘tish taqiqlangan hududning oxiri', '', '3.21_resize-min.png.webp', 76),
('3.22', 'Taqiqlovchi belgilar', 'Yuk avtomobillarida quvib o‘tish taqiqlangan', 'To‘liq vazni 3,5 tonnadan ortiq bo‘lgan yuk avtomobillarida barcha transport vositalarini quvib o‘tish taqiqlanishini bildiradi (soatiga 40 km dan kam tezlikda harakatlanayotgan transport vositasi, traktor, ot-arava, velosiped bundan mustasno).', '3.22_resize-min.png.webp', 77),
('3.23', 'Taqiqlovchi belgilar', 'Yuk avtomobillarida quvib o‘tish taqiqlangan hududning oxiri', '', '3.23.1_resize-min.png.webp', 78),
('3.24', 'Taqiqlovchi belgilar', 'Yuqori tezlik cheklangan', 'Belgida ko‘rsatilganidan ortiq tezlikda (km/s) harakatlanish taqiqlanishini bildiradi.', '3.24_resize-min.png.webp', 79),
('3.25', 'Taqiqlovchi belgilar', 'Yuqori tezlik cheklangan hududning oxiri', '', '3.25_resize-min.png.webp', 80),
('3.26', 'Taqiqlovchi belgilar', 'Tovush moslamalaridan foydalanish taqiqlangan', 'Yo‘l transport hodisasining oldini olish hollaridan boshqa vaziyatlarda tovush moslamasidan foydalanish taqiqlanadi.', '3.26_resize-min.png.webp', 81),
('3.27', 'Taqiqlovchi belgilar', 'To‘xtash taqiqlangan', 'Transport vositalarining to‘xtashi va to‘xtab turishi taqiqlanadi (xizmat vazifasini bajarayotgan xodimga biriktirilgan ko‘k yoki qizil yoxud ko‘k va qizil rangli yaltiroq mayoqchasi bilan jihozlangan hamda maxsus rangli bo‘yoq sxemalar va yozuvlar bilan belgilangan transport vositalari bundan mustasno).', '3.27_resize-min.png.webp', 82),
('3.28', 'Taqiqlovchi belgilar', 'To‘xtab turish taqiqlangan', 'Transport vositalarining to‘xtab turishi taqiqlanadi (xizmat vazifasini bajarayotgan xodimga biriktirilgan ko‘k yoki qizil yoxud ko‘k va qizil rangli yaltiroq mayoqchasi bilan jihozlangan hamda maxsus rangli bo‘yoq sxemalar va yozuvlar bilan belgilangan transport vositalari bundan mustasno).', '3.28_resize-min.png.webp', 83),
('3.29', 'Taqiqlovchi belgilar', 'Oyning toq kunlarida to‘xtab turish taqiqlangan', '(xizmat vazifasini bajarayotgan xodimga biriktirilgan ko‘k yoki qizil yoxud ko‘k va qizil rangli yaltiroq mayoqchasi bilan jihozlangan hamda maxsus rangli bo‘yoq sxemalar va yozuvlar bilan belgilangan transport vositalari bundan mustasno).', '3.29_resize-min.png.webp', 84),
('3.30', 'Taqiqlovchi belgilar', 'Oyning juft kunlarida to‘xtab turish taqiqlangan', '(xizmat vazifasini bajarayotgan xodimga biriktirilgan ko‘k yoki qizil yoxud ko‘k va qizil rangli yaltiroq mayoqchasi bilan jihozlangan hamda maxsus rangli bo‘yoq sxemalar va yozuvlar bilan belgilangan transport vositalari bundan mustasno).3.29 va 3.30 belgilari qatnov qismining qarama-qarshi tomonlarida bir vaqtda o‘rnatilganda, qatnov qismining har ikkala tomonida soat 19:00 dan 21:00 gacha to‘xtab turishga ruxsat etiladi (joyini o‘zgartirish vaqti).', '3.30_resize-min.png.webp', 85),
('3.31', 'Taqiqlovchi belgilar', 'Barcha cheklovlarning oxiri', '3.16, 3.20, 3.22, 3.24, 3.26 — 3.30 belgilaridan bir nechtasiga bir vaqtda amal qiladigan hududlarning oxiri.', '3.31_resize-min.png.webp', 86),
('3.32', 'Taqiqlovchi belgilar', 'Xavfli yuk tashiyotgan transport vositasining harakati taqiqlangan', '', '3.32_resize-min.png.webp', 87),
('3.33', 'Taqiqlovchi belgilar', 'Portlovchi va tez alangalanuvchi yukni tashiyotgan transport vositasining harakati taqiqlangan', '', '3.33_resize-min.png.webp', 88),
