('4.3', 'Buyuruvchi belgilar', 'Aylanma harakatlanish', 'Ko‘rsatkichlar yo‘nalishlarida harakatlanish ruxsat etiladi.', '4.3_resize-min.png.webp', 98),
('4.4', 'Buyuruvchi belgilar', 'Yengil avtomobillar harakati', 'Yengil avtomobillar, avtobus, mototsikllar, belgilangan yo‘nalishli transport vositalari va ruxsat etilgan to‘liq vazni 3,5 tonnadan oshmaydigan yuk avtomobillari harakatlanishiga ruxsat etilishini bildiradi. Belgining ta’sir oralig‘ida yashovchi va ishlovchi fuqarolarga tegishli, ularga va korxonalarga xizmat ko‘rsatuvchi transport vositalariga bu belgi tatbiq etilmaydi. Bunday hollarda transport vositalari belgilangan joyga eng yaqin chorrahadan kirib yoki chiqib ketishlari kerak.', '4.4_resize-min.png.webp', 99),
('4.5', 'Buyuruvchi belgilar', 'Velosiped yo‘lkasi', 'Faqat velosiped va mopedlarda harakatlanishga ruxsat etilishini bildiradi. Trotuar yoki piyodalar yo‘lkasi bo‘lmasa, velosiped yo‘lkasidan piyodalar ham yurishlari mumkin.', '4.5_resize-min.png.webp', 100),
('4.6', 'Buyuruvchi belgilar', 'Piyodalar yo‘lkasi', 'Faqat piyodalar yurishiga ruxsat etiladi.', '4.6.0_resize-min.png.webp', 101),
('4.6.1', 'Buyuruvchi belgilar', 'Piyodalar va velosipedchilarning birgalikdagi harakati tashkil etilgan yo‘lak', '', '4.6.1_resize-min.png.webp', 102),
('4.6.2', 'Buyuruvchi belgilar', 'Piyodalar va velosipedchilarning birgalikdagi harakati tashkil etilgan yo‘lakning oxiri', '', '4.6.2_resize-min.png.webp', 103),
('4.6.3', 'Buyuruvchi belgilar', 'Piyodalar va velosipedchilarning harakati alohida tashkil etilgan yo‘lak', '1.1, 1.25 va 1.26 yotiq yo‘l chizig‘i yordamida, konstruktiv tarzda yoxud boshqa usulda piyodalar va velosipedchilarning harakati ajratilgan piyodalar va velosipedchilar yo‘lagi.', '4.6.3_resize-min.png.webp', 104),
('4.6.4', 'Buyuruvchi belgilar', 'Piyodalar va velosipedchilarning harakati alohida tashkil etilgan yo‘lakning oxiri', '', '4.6.4_resize-min.png.webp', 105),
('4.6.5', 'Buyuruvchi belgilar', 'Piyodalar va velosipedchilarning harakati alohida tashkil etilgan yo‘lak', '1.1, 1.25 va 1.26 yotiq yo‘l chizig‘i yordamida, konstruktiv tarzda yoxud boshqa usulda piyodalar va velosipedchilarning harakati ajratilgan piyodalar va velosipedchilar yo‘lagi.', '4.6.5_resize-min.png.webp', 106),
