('4.7', 'Buyuruvchi belgilar', 'Eng kam tezlik', 'Faqat belgida ko‘rsatilgan yoki undan yuqori tezlikda (km/soat) harakatlanishga ruxsat etilishini bildiradi.', '4.7_resize-min.png.webp', 108),
('4.8', 'Buyuruvchi belgilar', 'Eng kam tezlik belgilangan yo‘lning oxiri', '', '4.8_resize-min.png.webp', 109),
('4.9.1', 'Buyuruvchi belgilar', 'Xavfli yuk tashiyotgan transport vositalarining harakat yo‘nalishi', '«Xavfli yuk» tanish belgisi bilan jihozlangan transport vositalarining harakatiga yo‘l belgisida ko‘rsatilgan yo‘nalishlarda ruxsat beriladi: to‘g‘riga.', '4.9.1_resize-min.png.webp', 110),
('4.9.2', 'Buyuruvchi belgilar', 'Xavfli yuk tashiyotgan transport vositalarining harakat yo‘nalishi', '«Xavfli yuk» tanish belgisi bilan jihozlangan transport vositalarining harakatiga yo‘l belgisida ko‘rsatilgan yo‘nalishlarda ruxsat beriladi: chapga.', '4.9.2_resize-min.png.webp', 111),
