('5.1', 'Axborot belgilari', 'Avtomagistral', 'Yo‘l harakati qoidalarining avtomagistrallarda harakatlanish tartibi o‘rnatilgan yo‘lni bildiradi.', '5.1_resize-min.png.webp', 113),
('5.2', 'Axborot belgilari', 'Avtomagistralning oxiri', '', '5.2_resize-min.png.webp', 114),
('5.3', 'Axborot belgilari', 'Avtomobillar uchun mo‘ljallangan yo‘l', 'Faqat avtomobillar, avtobus va mototsikllarning harakatlanishi uchun mo‘ljallangan yo‘lni bildiradi.', '5.3_resize-min.png.webp', 115),
