('5.21.1', 'Axborot belgilari', 'Yo‘nalish ko‘rsatkichi', '', '5.21_resize-min.png.webp', 151),
('5.21.2', 'Axborot belgilari', 'Yo‘nalishlar ko‘rsatkichi', 'Ko‘rsatilgan manzillarga harakatlanish yo‘nalishlarini bildiradi. Belgilarda manzillargacha bo‘lgan masofa (km) ko‘rsatilishi, avtomagistrallar, aeroportlar va boshqa ramziy belgilar tasvirlangan bo‘lishi mumkin.', '5.21.2_resize-min.png.webp', 152),
('5.22', 'Axborot belgilari', 'Aholi punktining boshlanishi', 'Ushbu Qoidalarning aholi punktlarida harakatlanish tartibini belgilovchi talablariga amal qilinadigan joylarning nomi hamda uning boshlanishini bildiradi.', '5.22_resize-min.png.webp', 153),
('5.23', 'Axborot belgilari', 'Aholi punktining oxiri', 'Ushbu Qoidalarning aholi punktlarida harakatlanish tartib-talablari bekor qilingan joyni bildiradi.', '5.23_resize-min.png.webp', 154),
