('5.26', 'Axborot belgilari', 'Manzil nomi', 'Aholi punktlaridan boshqa manzillarning nomini bildiradi (daryo, ko‘l, dovon, xushmanzara joy va boshqalar).', '5.26_resize-min.png.webp', 156),
('5.27', 'Axborot belgilari', 'Masofalar ko‘rsatkichi', 'Yo‘nalish bo‘yicha joylashgan aholi punktlarigacha bo‘lgan masofani bildiradi (km).', '5.27_resize-min.png.webp', 157),
('5.28', 'Axborot belgilari', 'Kilometr belgisi', 'Yo‘lning boshi yoki oxirigacha bo‘lgan masofani bildiradi (km).', '5.28_resize-min.png.webp', 158),
