('5.29.2', 'Axborot belgilari', 'Yo‘l raqami', 'Yo‘lning raqami va yo‘nalishini bildiradi.', '5.29.2_resize-min.png.webp', 160),
('5.30.1 – 5.30.3', 'Axborot belgilari', 'Yuk avtomobillari uchun harakatlanish yo‘nalishi', 'Chorrahada yuk avtomobillari, traktorlar va o‘ziyurar moslamalarga biror yo‘nalishda harakatlanish taqiqlangan bo‘lsa, bunday transport vositalariga tavsiya etilgan harakatlanish yo‘nalishlari ko‘rsatadi.', '5.30_resize-min.png.webp', 161),
('5.31', 'Axborot belgilari', 'Aylanib o‘tish tasviri', 'Harakatlanish uchun vaqtincha yopib qo‘yilgan yo‘l qismini chetlab o‘tish chizmasi.', '5.31_resize-min.png.webp', 162),
