('5.33', 'Axborot belgilari', 'To‘xtash chizig‘i', 'Svetoforning (tartibga soluvchining) taqiqlovchi ishorasida transport vositalari to‘xtaydigan yo‘nalishini bildiradi.', '5.33_resize-min.png.webp', 164),
('5.34.1 – 5.34.2', 'Axborot belgilari', 'Boshqa qatnov qismiga qayta tizilishning boshlang‘ich ko‘rsatkichi', 'Ajratuvchi bo‘lagi bo‘lgan yo‘lning harakatlanish uchun yopiq hududini aylanib o‘tish yoki o‘ng tomondagi qatnov qismiga qaytish uchun harakatlanish yo‘nalishini bildiradi.', '5.34.1_resize-min.png.webp', 165),
('5.35', 'Axborot belgilari', 'Reversiv harakatlanish', 'Bir yoki bir necha tasmalarda harakatlanish yo‘nalishi qarama-qarshi tomonga o‘zgarishi mumkin bo‘lgan yo‘l qismining boshlanishini bildiradi.', '5.35_resize-min.png.webp', 166),
('5.36', 'Axborot belgilari', 'Reversiv harakatlanishning oxiri', '', '5.36_resize-min.png.webp', 167),
('5.37', 'Axborot belgilari', 'Reversiv harakatlanish yo‘liga chiqish', '', '5.37_resize-min.png.webp', 168),
('5.38', 'Axborot belgilari', 'Turar joy dahasi', 'Yo‘l harakati qoidalarining turar joy dahalarida harakatlanish tartibi o‘rnatilgan yo‘l.', '5.38_resize-min.png.webp', 169),
('5.39', 'Axborot belgilari', 'Turar joy dahasining oxiri', '', '5.39_resize-min.png.webp', 170),
('5.40', 'Axborot belgilari', 'Falokatli holatlar uchun kirish yo‘li', 'Yo‘l harakati ushbu Qoidalaridagi 128-bandda ko‘rsatilgan holatlarda foydalaniladigan yo‘l.', '5.40_resize-min.png.webp', 171),
('5.41', 'Axborot belgilari', 'Foto va video qayd etish', 'Yo‘llarda avtomobil haydovchilari Qoidalar talabiga rioya etishi elektron qurilmalar yordamida nazorat qilinayotganligini bildiruvchi yo‘l belgisi. Ushbu yo‘l belgisi Qoidalar talabiga rioya etilishi statsionar elektron qurilmalar orqali nazoratga olingan joylarga o‘rnatiladi.', '5.41_resize-min.png.webp', 172),
('5.42', 'Axborot belgilari', 'Qizil chiroqda o‘ngga harakatlanish', 'Transport svetofori qizil chirog‘ining o‘ng yoniga 5.42 yo‘l belgisi o‘rnatilgan bo‘lsa, transport vositalarining haydovchilari svetoforning taqiqlovchi ishorasi yonib turganda, barcha xavfsizlik choralarini ko‘rgan holda o‘ngga burilishlari mumkin. Bunda ular harakat yo‘nalishi bo‘yicha va burilayotgan ko‘chani kesib o‘tayotgan piyodalarga hamda boshqa transport vositalariga yo‘l berishlari shart.', '5.42_resize-min.png.webp', 173),
('5.43', 'Axborot belgilari', 'Radar', 'Yo‘llarda avtomobil haydovchilari belgilangan tezlikka rioya etishi radarlar yordamida nazorat qilinayotganligini bildiruvchi yo‘l belgisi. Ushbu yo‘l belgisi belgilangan harakatlanish tezligi statsionar maxsus texnika vositalari yordamida nazoratga olingan joylarga o‘rnatiladi. Shuningdek, viloyat, tuman, shaharlar boshlanadigan joylardagi ko‘cha va yo‘llarda harakatlanish tezligi mobil radarlar yordamida nazorat qilinayotganligi to‘g‘risida haydovchilarni ogohlantirish maqsadida o‘rnatilishi mumkin.', '5.43_resize-min.png.webp', 174),
('5.44', 'Axborot belgilari', 'Velosipedchilar uchun tasma', '', '5.44_resize-min.png.webp', 175),
('5.45', 'Axborot belgilari', 'Velosipedchilar uchun tasmaning oxiri', '', '5.45_resize-min.png.webp', 176),
('5.46', 'Axborot belgilari', 'Maktab', 'Maktab yoki maktabgacha ta’lim tashkilotlari oldida o‘rnatiladi.', '5.46_resize-min.png.webp', 177),
('5.47', 'Axborot belgilari', 'Turizm obyektlari yo‘nalish ko‘rsatgichi', 'Turizm obyektlari joylashgan manzillarga harakatlanish yo‘nalishlarini bildiradi. Belgilarda manzillargacha bo‘lgan masofa (km) ko‘rsatilishi, temir yo‘l vokzallari, aeroportlar va boshqa turizm obyektlari ramziy belgilari tasvirlangan bo‘lishi mumkin.', '5.47_resize-min.png.webp', 178),
