('7.1.1', 'Qo’shimcha axborot belgilari', 'Obyektgacha bo‘lgan masofa', 'Belgidan yo‘lning xavfli joyi, yo‘l harakatiga tegishli cheklovlar kiritiladigan joyi yoki harakat yo‘nalishi bo‘yicha oldindagi muayyan joygacha bo‘lgan masofani ko‘rsatadi.', '7.1.1_resize-min.png.webp', 212),
('7.1.2', 'Qo’shimcha axborot belgilari', 'Obyektgacha bo‘lgan masofa', 'Aholi punktlaridan tashqarida chorraha oldiga 2.5. yo‘l belgisi o‘rnatilgan bo‘lsa, 2.4. yo‘l belgisi bilan o‘rnatilib, chorrahagacha bo‘lgan masofani ko‘rsatadi.', '7.1.2_resize-min.png.webp', 213),
('7.1.3 – 7.1.4', 'Qo’shimcha axborot belgilari', 'Obyektgacha bo‘lgan masofa', 'Yo‘ldan chetda joylashgan manzilgacha bo‘lgan masofani bildiradi.', '7.1.3_resize-min.png.webp', 214),
('7.2.1', 'Qo’shimcha axborot belgilari', 'Ta’sir oralig‘i', 'Ogohlantiruvchi belgilar bilan belgilangan xavfli joyning uzunligini yoki taqiqlovchi va axborot-ko‘rsatkich belgilarining ta’sir oralig‘ini ko‘rsatadi.', '7.2.1_resize-min.png.webp', 215),
('7.2.2', 'Qo’shimcha axborot belgilari', 'Ta’sir oralig‘i', '3.27 — 3.30 taqiqlovchi belgilarining ta’siri saqlangan oraliqni ko‘rsatadi.', '7.2.2_resize-min-150x300.png.webp', 216),
('7.2.3', 'Qo’shimcha axborot belgilari', 'Ta’sir oralig‘i', '3.27 — 3.30 taqiqlovchi belgilarining ta’sir oralig‘i oxirini ko‘rsatadi.', '7.2.3_resize-min-150x300.png.webp', 217),
('7.2.4', 'Qo’shimcha axborot belgilari', 'Ta’sir oralig‘i', 'Haydovchilarga ularning 3.27 — 3.30 yo‘l belgilari ta’sir doirasida ekanliklari haqida axborot beradi.', '7.2.4_resize-min-150x300.png.webp', 218),
('7.2.5 – 7.2.6', 'Qo’shimcha axborot belgilari', 'Ta’sir oralig‘i', 'Maydon, binolar oldi va shunga o‘xshash joylar chetida to‘xtash va to‘xtab turish taqiqlanganda 3.27 — 3.30 belgilarining ta’sir oralig‘i va yo‘nalishini ko‘rsatadi.', '7.2.5_resize-min.png.webp', 219),
('7.3.1 – 7.3.3', 'Qo’shimcha axborot belgilari', 'Ta’sir yo‘nalishlari', 'Chorraha oldida o‘rnatilgan belgilarning ta’sir yo‘nalishini yoki bevosita yo‘l yaqinida joylashgan manzillarga harakatlanish yo‘nalishini ko‘rsatadi.', '7.3.1_resize-min.png.webp', 220),
('7.4.1 – 7.4.10', 'Qo’shimcha axborot belgilari', 'Transport vositasining turi', 'Belgining ta’siri joriy etilgan transport vositalari turini ko‘rsatadi. 7.4.1 belgi bilan o‘rnatilgan yo‘l belgisining ta’siri yuk tashuvchi, shu jumladan, tirkamali, to‘liq vazni 3,5 tonnadan ortiq bo‘lgan transport vositalariga, 7.4.3 belgi bilan o‘rnatilgan yo‘l belgisining ta’siri yengil avtomobillarga, 7.4.9 elektromobillarga, 7.4.10 yo‘nalishsiz taksilarga, shuningdek, to‘liq vazni 3,5 tonnagacha bo‘lgan yuk tashuvchi transport vositalariga tatbiq etiladi.', '7.4.1_resize-min.png.webp', 221),
('7.5.1', 'Qo’shimcha axborot belgilari', 'Shanba, yakshanba va bayram kunlari', '', '7.5.1_resize-min.png.webp', 222),
('7.5.2', 'Qo’shimcha axborot belgilari', 'Ish kunlari', '', '7.5.2_resize-min.png.webp', 223),
('7.5.3', 'Qo’shimcha axborot belgilari', 'Hafta kunlari', 'Belgiga haftaning qaysi kunlari amal qilinishi ko‘rsatilgan.', '7.5.3_resize-min.png.webp', 224),
('7.5.4', 'Qo’shimcha axborot belgilari', 'Amal qilish vaqti', 'Belgiga kunning qaysi vaqtida amal qilishni ko‘rsatadi.', '7.5.4_resize-min.png.webp', 225),
('7.5.5 – 7.5.7', 'Qo’shimcha axborot belgilari', 'Amal qilish vaqti', 'Belgiga haftaning qaysi kuni va qaysi soatlarida amal qilishni ko‘rsatadi.', '7.5.5_resize-min.png.webp', 226),
('7.6.1 – 7.6.9', 'Qo’shimcha axborot belgilari', 'Transport vositasini to‘xtab turish joyiga qo‘yish usuli', '7.6.1 barcha turdagi transport vositalarini to‘xtab turishi uchun yo‘lning qatnov qismida, trotuar yoniga qo‘yish usulini, 7.6.2 — 7.6.9 trotuar yonidagi to‘xtab turish joyiga yengil avtomobillar va mototsikllarni qo‘yish usulini bildiradi.', '7.6.1_resize-min.png.webp', 227),
('7.7', 'Qo’shimcha axborot belgilari', 'Dvigatelni ishlatmasdan to‘xtab turish joyi', '5.15 belgisi bilan belgilangan to‘xtab turish joyida transport vositalarining dvigatelini ishlatmasdan to‘xtab turishiga ruxsat etilganligini ko‘rsatadi.', '7.7_resize-min.png.webp', 228),
('7.8', 'Qo’shimcha axborot belgilari', 'Pulli xizmat ko‘rsatish joyi', 'To‘lov asosida xizmat ko‘rsatilishini bildiradi.', '7.8_resize-min.png.webp', 229),
('7.9', 'Qo’shimcha axborot belgilari', 'To‘xtab turish muddati cheklangan', '5.15 belgisi o‘rnatilgan to‘xtab turish joyida transport vositalari to‘xtab turishining eng ko‘p muddatini ko‘rsatadi.', '7.9_resize-min.png.webp', 230),
('7.10', 'Qo’shimcha axborot belgilari', 'Avtomobillarni ko‘rikdan o‘tkazish joyi', '5.15 yoki 6.11 belgisi bilan ko‘rsatilgan maydonlarda estakada yoki ko‘zdan kechirish chuqurchalari borligini bildiradi.', '7.10_resize-min.png.webp', 231),
('7.11', 'Qo’shimcha axborot belgilari', 'Ruxsat etilgan to‘la vazni cheklangan', 'Belgining ta’siri ruxsat etilgan to‘la vazni qo‘shimcha-axborot yo‘l belgisida ko‘rsatilgan miqdordan ortiq bo‘lgan transport vositalariga taalluqli ekanligini ko‘rsatadi.', '7.11_resize-min.png.webp', 232),
('7.12', 'Qo’shimcha axborot belgilari', 'Xavfli yo‘l yoqasi', 'Yo‘l ishlari bajarilayotgani sababli yo‘l yoqasiga chiqish xavfli ekanligi haqida ogohlantiradi. 1.23 belgisi bilan qo‘llaniladi.', '7.12_resize-min.png.webp', 233),
('7.13', 'Qo’shimcha axborot belgilari', 'Asosiy yo‘lning yo‘nalishi', 'Chorrahada asosiy yo‘lning yo‘nalishini ko‘rsatadi.', '7.13_resize-min-300x198.png.webp', 234),
('7.14', 'Qo’shimcha axborot belgilari', 'Harakatlanish tasmasi', 'Belgi yoki svetofor ta’siridagi harakatlanish bo‘lagini ko‘rsatadi.', '7.14_resize-min.png.webp', 235),
('7.15', 'Qo’shimcha axborot belgilari', 'Ko‘zi ojiz piyodalar', '1.20, 5.16.1, 5.16.2 belgilari hamda svetofor bilan birga qo‘llaniladi, piyodalar o‘tish joyidan ko‘zi ojiz piyodalar foydalanishi mumkinligi haqida ogohlantiradi.', '7.15_resize-min.png.webp', 236),
('7.16', 'Qo’shimcha axborot belgilari', 'Nam qoplama', 'Belgi qatnov qismining qoplamasi nam bo‘lgan vaqtda ta’sir etishini ko‘rsatadi.', '7.16_resize-min.png.webp', 237),
('7.17', 'Qo’shimcha axborot belgilari', 'Nogironlar', '5.15 belgisi bilan qo‘llaniladi. To‘xtab turish joyi (yoki uning bir qismi) ushbu Qoidalarning 176-bandiga muvofiq “Nogiron” taniqlik belgisi o‘rnatilgan transport vositalari uchun ajratilganligini ko‘rsatadi.', '7.17_resize-min.png.webp', 238),
('7.18', 'Qo’shimcha axborot belgilari', 'Nogironlar mustasno', 'Belgilarning ta’siri ushbu Qoidalarning 175-bandiga muvofiq “Nogiron” taniqlik belgisi o‘rnatilgan transport vositalariga joriy etilmaydi.', '7.18_resize-min.png.webp', 239),
('7.19', 'Qo’shimcha axborot belgilari', 'Foto va video qayd etish', 'Yo‘l harakati qatnashchilarining harakatlari maxsus avtomatlashtirilgan foto va video qayd etish texnika vositalari orqali qayd etilayotganligini bildiradi. Ogohlantiruvchi, imtiyoz, taqiqlovchi, buyuruvchi va axborot ishora belgilari bilan birgalikda qo‘llaniladi.', '7.19_resize-min.png.webp', 240),
('7.20', 'Qo’shimcha axborot belgilari', 'Xavfli yuk toifasi', 'Xavfli yuk toifasining (toifalarining) raqamini ko‘rsatadi.', '7.20_resize-min.png.webp', 241),
('7.21', 'Qo’shimcha axborot belgilari', 'Evakuator ishlamoqda', '3.27 — 3.30 yo‘l belgilari ta’sir oralig‘ida to‘xtagan transport vositalari majburiy evakuatsiya qilinishini ko‘rsatadi.', '7.21_resize-min.png.webp', 242),
('7.22.1 – 7.22.3', 'Qo’shimcha axborot belgilari', 'To‘siq', 'Haydovchilarga to‘siqning uzoqdan ko‘rinishini ta’minlash maqsadida o‘rnatiladi. 4.2.1 — 4.2.3 yo‘l belgilari bilan birgalikda o‘rnatiladi.', '7.22_resize-min-141x300.png.webp', 243),
