-- Foydali ma'lumotlar: traffic sign reference (number, category, title, description, image).
-- Images live in the public 'foydali malumotlar' Supabase Storage bucket (created manually
-- by the site owner), image_path stores just the filename within that bucket.

CREATE TABLE public.traffic_signs (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  number text NOT NULL,
  category text NOT NULL,
  title text NOT NULL,
  description text NOT NULL DEFAULT '',
  image_path text,
  order_index integer NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE public.traffic_signs ENABLE ROW LEVEL SECURITY;
-- No policies: only edge functions (service-role key) touch this table.
CREATE INDEX idx_traffic_signs_category ON public.traffic_signs (category, order_index);

